public int nextInt(int n) {
        if (n <= 0 ) {
            throw MathRuntimeException.createIllegalArgumentException(
                  LocalizedFormats.NOT_POSITIVE_UPPER_BOUND, n);
        }
        int result = (int) (nextDouble() * n);
        return result < n ? result : n - 1;
    }

